"""
mkt-original — Genesis chapters 29-30
Run: python3 scripts/zc-original-genesis-29-30.py

Key linguistic coverage:
- Ch 29: nasa raglav "lifted his feet" (v1); well-meeting type-scene conventions (v2-3);
  rach — soft/weak eyes ambiguity for Leah (v17); yephat-toar/mareh beauty double formula (v17);
  atsmî uvasarî — flesh-and-blood kinship formula (v14); Jacob-deceived wordplay mirroring
  ch 27 (v25); senuah — "hated" as comparative idiom (v31); womb-opening formula (v31);
  Reuben/raah+ben (v32), Simeon/shama (v33), Levi/lavah (v34), Judah/yadah (v35)
- Ch 30: habhah-li vanim cry (v1); Am-I-in-place-of-God formula (v2); yeled al-birkkay
  adoption ritual (v3); Dan/din (v6); Naphtali/pathal — wrestler etymology anticipating
  Peniel (v8); Gad/fortune (v11); Asher/esher (v13); dudaim mandrakes as aphrodisiac
  cultural background (v14); Issachar/sakar wages (v18); Zebulun/zabal (v20); God
  remembered Rachel — zakar covenant formula (v22); Joseph dual etymology: asaph/yoseph (v23-24);
  branch-breeding scheme and its reinterpretation in 31:10-13 (v37-43)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_ORIGINAL = {
  "29": {
    "1": """<p><strong>wayyiśśāʾ yaʿăqōḇ raglāyw</strong> — "Jacob lifted his feet." The MKT renders this "continued on his journey," but the literal is more vivid: <em>nāśāʾ raglāyw</em> (to lift one's feet) is an idiom for setting out with energy and purpose — the feet are lifted rather than dragged. The phrase captures Jacob's renewed momentum after the Bethel theophany (28:10-22); he departs with the covenant promise fresh in his ears. The expression appears only here and in Ezek 1:7 (for the living creatures' straight legs) — it is unusual enough to be marked as a deliberate stylistic choice by the narrator.</p>""",
    "2": """<p><strong>wayyarʾ wĕhinnēh bĕʾēr baśśāḏeh</strong> — "And he saw — and behold — a well in the field." The narrative well-meeting is a recognized type-scene in biblical literature: a young man travels to a foreign land, meets a young woman at a well, a betrothal follows (cf. Abraham's servant and Rebekah, 24:11-27; Moses and Zipporah, Exod 2:15-21). The exclamatory <em>hinnēh</em> (behold!) marks the moment of recognition — the well is the narrative signal that a betrothal-meeting is about to occur. The large stone (<em>ʾeḇen gĕḏōlāh</em>) over the well's mouth is the obstacle that will display Jacob's strength and eagerness in v10.</p>""",
    "3": """<p><strong>wĕnĕʾespû-šāmmāh kol-hāʿĕḏārîm wĕgālălû ʾet-hāʾeḇen</strong> — "When all the flocks were gathered, they would roll the stone." The communal requirement — all flocks assembled before the stone is moved — establishes a social norm that Jacob will violate in v10 (rolling the stone alone, before all flocks arrive). The Qal perfect verbs here describe habitual action (<em>wĕnĕʾespû... wĕgālălû</em>): what was customarily done. The stone's communal guarding of the water reflects a water-rights culture in which shared wells had strict rules of access — one group could not monopolize the water at the expense of others.</p>""",
    "4": """<p><strong>ʾaḥay mēʾayin ʾattem</strong> — "My brothers, where are you from?" Jacob's address <em>ʾaḥay</em> (my brothers) is the conventional greeting to strangers of one's approximate social standing in the biblical world — not claiming literal kinship but establishing social solidarity. The inquiry about origin (<em>mēʾayin ʾattem</em>) is the standard opening of a self-identification dialogue — the same pattern in Ruth 2:5 (Boaz's inquiry about Ruth) and 1 Sam 30:13 (David's inquiry of the Egyptian servant). The dialogue format (question / answer / question / answer) follows the convention of biblical encounter narratives.</p>""",
    "5": """<p><strong>hăyĕḏaʿtem ʾet-lāḇān ben-nāḥôr</strong> — "Do you know Laban, son of Nahor?" Jacob identifies Laban by grandfather rather than by father (Bethuel) — possibly because Nahor was more well-known as the founder of the clan, or because Bethuel's status in the narrative was reduced (he appears only briefly in 24:50). The verb <em>yāḏaʿ</em> (to know) in this inquiry is social knowledge — do you recognize/know who he is? The affirmative answer (<em>yāḏāʿnû</em>, "we know him") uses the same verb, confirming that they have direct acquaintance with him.</p>""",
    "6": """<p><strong>hăšālôm lô</strong> — "Is he well?" The idiom <em>šālôm lô</em> (is it peace/wholeness to him?) is the standard Hebrew greeting inquiry — not a casual "how is he" but a covenantal inquiry about the total wellbeing of a person. <em>Šālôm</em> (H7965) encompasses physical health, social harmony, relational wholeness. The shepherds' answer (<em>šālôm</em> — "peace/well") completes the formulaic exchange. The additional information — "here comes his daughter Rachel with the sheep" — arrives as confirmation while Jacob is still processing the positive answer; the narrative timing creates suspense.</p>""",
    "7": """<p><strong>lōʾ-ʿēt hēʾāsep hammiqneh</strong> — "It is not time for the livestock to be gathered." Jacob's instruction to the shepherds (water the sheep and take them back to pasture) is either a desire for privacy with Rachel, or a reflection of his knowledge of pastoral customs that the shepherds are flouting. The observation about the sun still being high (<em>gāḏôl hayyôm</em>, the day is great/big) uses the same adjective (<em>gāḏôl</em>) as the greatness of the stone in vv2-3 — the great stone, the great day — both obstacles to the encounter Jacob wants.</p>""",
    "8": """<p><strong>lōʾ nûḵal ʿaḏ ʾăšer yēʾāsĕpû kol-hāʿĕḏārîm</strong> — "We cannot, until all the flocks are gathered." The shepherds' response appeals to the communal water-rights custom of v3 — the stone cannot be moved by less than the full assembly. The social constraint creates dramatic irony: Jacob is about to violate the very rule they cite by rolling the stone alone. Their "we cannot" (<em>lōʾ nûḵal</em>) is answered by Jacob's unilateral action in v10 — what the community could not do alone, Jacob does for love.</p>""",
    "9": """<p><strong>wĕrāḥēl bāʾāh ʿim-haṣṣōʾn ʾăšer lĕʾāḇîhā kî rōʿāh hîʾ</strong> — "Rachel came with her father's flock, for she was their shepherdess." The word <em>rōʿāh</em> (shepherdess, Qal feminine participle of <em>rāʿāh</em>) is unusual — women shepherds appear in biblical narrative at significant moments (Moses's future wife Zipporah is a shepherdess in Exod 2:16-17; the Song of Solomon's beloved is associated with pastoral imagery). The feminine participle here marks Rachel's role as active keeper of the flock — she is tending, not merely accompanying. The temporal phrase "while he was still talking with them" compresses the timing so that Rachel's arrival is simultaneous with the failed instruction to the shepherds.</p>""",
    "10": """<p><strong>wayyāgar yaʿăqōḇ wayyāgel ʾet-hāʾeḇen</strong> — "Jacob went over and rolled the stone." The verse breaks the communal rule established in vv3 and 8: Jacob rolls the stone alone, immediately, without waiting for all flocks to gather. The verb <em>gālal</em> (H1556, to roll, to roll away) will recur at the naming of Galeed (31:47-48) and Galilee's association with rolling/revealing. The physical act of single-handedly moving what normally required the assembled community is a display of extraordinary strength driven by emotional urgency. Notably, Jacob does this for his uncle's sheep, not his own — the act is an unrequested gift of labor, foreshadowing the fourteen years of service he will give to Laban.</p>""",
    "11": """<p><strong>wayyiššaq yaʿăqōḇ lĕrāḥēl wayyiśśāʾ ʾet-qōlô wayyēḇk</strong> — "Jacob kissed Rachel and raised his voice and wept." The kiss (<em>nāšaq</em>, H5401, to kiss; also used for battle-joining and equipment-touching — a contact verb) and the weeping are simultaneous. <em>Wayyiśśāʾ ʾet-qōlô</em> — "he raised his voice" — is the standard idiom for crying aloud (cf. 21:16 for Hagar's weeping; 27:38 for Esau's cry). Jacob's tears are explained in v12 — it is the recognition of finding his family after the flight from home. The emotional rawness of the moment is preserved without editorializing — the narrator does not explain the tears; the reader fills in the isolation, fear, and relief that generated them.</p>""",
    "12": """<p><strong>wayyaggēḏ lĕrāḥēl kî ʾăḥî ʾāḇîhā hûʾ wĕḵî ben-riqāh hûʾ</strong> — "He told Rachel that he was a kinsman of her father and a son of Rebekah." The word <em>ʾāḥ</em> (brother/kinsman, H251) is used broadly in Hebrew for both siblings and extended kin — Jacob is actually a nephew of Laban, not a brother. The term <em>ʾăḥî ʾāḇîhā</em> ("kinsman of her father") is the narrator's gloss of what Jacob said; the fuller kinship identifier "son of Rebekah" (Laban's sister) establishes the genealogical connection that will ground the subsequent labor-covenant.</p>""",
    "13": """<p><strong>wayyārāṣ liqrāʾtô wayyĕḥabbēq-lô wayyĕnaššeq-lô</strong> — "He ran to meet him, and embraced him, and kissed him." Laban's greeting uses the same three verbs — run (<em>rûṣ</em>), embrace (<em>ḥābaq</em>), kiss (<em>nāšaq</em>) — that will appear in the father's reception of the prodigal son in Luke 15:20 (and in Abraham's servant's reception in 24:29-31, another Laban episode). The warm reception may reflect genuine hospitality or, as the narrative will reveal, Laban's recognition of a useful kinsman. <em>Wayyĕsappēr lĕlāḇān ʾēt kol-haddĕḇārîm hāʾēlleh</em> — "Jacob told him all these things" — the contents of the telling are not specified; the reader is left to imagine the account of the deception, flight, and Bethel theophany that constitute Jacob's recent history.</p>""",
    "14": """<p><strong>ʾaḵ ʿaṣmî ûḇĕśārî ʾattāh</strong> — "Surely you are my bone and my flesh." Laban's kinship declaration uses the same formula Adam used for Eve in 2:23 (<em>ʿeṣem mēʿăṣāmay ûḇāśār mibĕśārî</em>, "bone of my bones and flesh of my flesh") — the formula of belonging-by-substance. In 2:23 the formula establishes marriage; here it establishes covenant kinship. The words will acquire ironic weight in the subsequent narrative: the one who claims Jacob as bone and flesh will exploit him for twenty years. <em>Ḥōḏeš yāmîm</em> — "a month of days" — the Hebrew idiom for a full month; the time-reckoning before the labor-covenant is proposed.</p>""",
    "15": """<p><strong>kî-ʾāḥî ʾattāh waʿăḇaḏtanî ḥinnām haggîḏāh-lî mah-maškoroteyḵā</strong> — "Just because you are my kinsman, should you work for me for nothing? Tell me what your wages should be." Laban's framing is ostensibly generous: kinship should not mean free labor. But the question shifts the relationship from household-kinship (where Jacob might legitimately expect hospitality) to labor-contract. The word <em>māśkōret</em> (H4909, wages, remuneration from <em>śāḵar</em> = to hire) introduces the commercial register that will dominate the Jacob-Laban relationship. Laban's opening move to set wages — when Jacob has not asked for pay — reveals his calculative nature: he wants to fix the terms before Jacob's expectations grow.</p>""",
    "16": """<p><strong>ûlĕlāḇān šĕtê ḇānôt šēm hāgĕḏōlāh lēʾāh wĕšēm haqqĕṭannāh rāḥēl</strong> — "Laban had two daughters; the name of the elder was Leah, and the name of the younger was Rachel." The narrator introduces both daughters at this point to set up the deception of v23. The age-ordering — elder (<em>gĕḏōlāh</em>) Leah, younger (<em>qĕṭannāh</em>) Rachel — echoes the elder-younger tension that runs throughout Genesis: Cain/Abel, Ishmael/Isaac, Esau/Jacob. The names: <em>Lēʾāh</em> may derive from an Akkadian cognate for "wild cow" or a Hebrew word for "weary"; <em>Rāḥēl</em> = "ewe" (the young female sheep) — both names are pastoral, fitting the shepherd family.</p>""",
    "17": """<p><strong>wĕʿênê lēʾāh rakkôt wĕrāḥēl hāyĕtāh yĕpat-tōʾar wîpat marʾeh</strong> — "Leah's eyes were soft/weak, but Rachel was beautiful in form and beautiful in appearance." The description of Leah's eyes is the most-debated phrase in this chapter: <em>rakkôt</em> (H7390, tender, soft, weak) applied to eyes can mean: (a) tender/lovely — eyes with a gentle, pleasing quality (a compliment in some ANE traditions); (b) weak/dull — eyes lacking the luster that ancient beauty standards prized. Most modern translators choose the negative reading because it contrasts with Rachel's beauty. The double beauty formula for Rachel — <em>yĕpat-tōʾar</em> (beautiful of form/shape) and <em>yĕpat marʾeh</em> (beautiful of appearance/face) — is the superlative double used elsewhere only for Joseph (39:6, <em>yĕpeh-tōʾar wîpeh marʾeh</em>) and Esther (2:7). Rachel and Joseph share the same beauty formula, another connection between mother and son.</p>""",
    "18": """<p><strong>wayyeʾĕhaḇ yaʿăqōḇ ʾet-rāḥēl wayyōʾmer ʾeʿĕḇāḏĕḵā šeḇaʿ šānîm bĕrāḥēl bittĕḵā haqqĕṭannāh</strong> — "Jacob loved Rachel and said, 'I will serve you seven years for Rachel your younger daughter.'" The verb <em>ʾāhaḇ</em> (to love) is stated before any marriage discussion — love precedes and grounds the labor-contract. Jacob's offer is extraordinarily high: the standard bride-price (<em>môhar</em>) was thirty shekels of silver (Deut 22:29); seven years of labor at a typical daily wage was worth far more. The specificity "your younger daughter" (<em>bittĕḵā haqqĕṭannāh</em>) is Jacob's legally precise identification — naming Rachel by birth-order specifically so there is no ambiguity. Laban's subsequent deception will exploit exactly this contractual specificity.</p>""",
    "19": """<p><strong>ṭôḇ tittî ʾōtāh lĕḵā mimmittî ʾōtāh lĕʾîš ʾaḥēr šĕḇāh ʿimmādî</strong> — "It is better that I give her to you than to another man. Stay with me." Laban's acceptance is conditional only that Jacob stay — he does not explicitly promise to give Rachel, a legally significant evasion. He says <em>tittî ʾōtāh lĕḵā</em> (I will give her to you) — apparently confirming the covenant — but the lack of explicit naming of which daughter will later be exploited. The parallel between Laban's deception of Jacob and Jacob's deception of Isaac is structural: both involve a covered identity, a darkened or confused setting, and the wrong person receiving what was promised to another.</p>""",
    "20": """<p><strong>wayyihyû bĕʿênāyw kĕyāmîm ʾăḥāḏîm bĕʾahaḇātô ʾōtāh</strong> — "They were in his eyes like a few days, in his love for her." The phrase <em>kĕyāmîm ʾăḥāḏîm</em> (like a few days, like individual days) is psychologically acute: prolonged time subjectively compressed by intense love. The preposition <em>bĕʾahaḇātô</em> (in his loving of her) — the Qal infinitive construct — makes the love the instrument of the temporal distortion. Seven years of labor became experientially negligible because of love's transformation of experience. This is one of the most celebrated compressed love-statements in world literature — the understatement is the point.</p>""",
    "21": """<p><strong>hāḇāh ʾet-ʾišĕtî kî mālĕʾû yāmāy wĕʾāḇôʾāh ʾēleyhā</strong> — "Give me my wife, for my days are fulfilled, and I will go in to her." Jacob's demand uses the legal formula <em>mālĕʾû yāmāy</em> ("my days are full/completed") — the fulfillment of the contractual term. The verb <em>mālaʾ</em> (H4390, to fill, complete) signals legal completion. <em>ʾĀḇôʾāh ʾēleyhā</em> — "I will come to her" — the idiom for sexual consummation of marriage (cf. 6:4; 16:2; 38:8). Jacob's directness is not rude but legally assertive: the contract is complete; the transfer of the wife should now occur.</p>""",
    "22": """<p><strong>wayyeʾĕsōp lāḇān ʾet-kol-ʾanĕšê hammāqôm wayyaʿaś mišteh</strong> — "Laban gathered all the men of the place and made a feast." The wedding feast (<em>mišteh</em>, H4960, drinking feast, from <em>šātāh</em>, to drink) was the public covenant ratification of marriage in the ANE — analogous to the covenant meals of diplomatic agreements (26:30; 31:54). The communal gathering ("all the men of the place") establishes the public witness that makes the marriage legally valid. The feast is also the cover for Laban's deception: in the evening darkness, after the drinking, the wrong daughter is brought.</p>""",
    "23": """<p><strong>wayhî ḇāʿereḇ wayyiqqaḥ ʾet-lēʾāh bittô wayyāḇēʾ ʾōtāh ʾēlāyw</strong> — "In the evening he took his daughter Leah and brought her to him." The deception operates by darkness (<em>ḇāʿereḇ</em>, in the evening) — the same mechanism Jacob used against his blind father: concealed identity in a dark room. Jacob blinded his father with goat skins and a deceptive voice; Laban blinds Jacob with darkness and a veil. The verb <em>wayyāḇēʾ</em> (he brought) mirrors the language of bringing the bride (v23) but with the wrong subject — it is the father bringing, not the bride coming voluntarily. The irony is structural and explicit: the deceiver is deceived with the same method he used.</p>""",
    "24": """<p><strong>wayyittēn lāḇān lāh ʾet-zilpāh šipĕḥātô lĕlēʾāh bittô šipĕḥāh</strong> — "Laban gave his servant Zilpah to his daughter Leah as her servant." The parenthetical note introduces Zilpah, who will become the mother of Gad and Asher (30:9-13). The gift of a servant to a daughter upon marriage was standard ANE custom — the servant formed part of the bride's dowry. Bilhah will similarly be given to Rachel (v29). Both servants-turned-surrogate-mothers are introduced at their respective marriages; their role in the birth-narrative of ch 30 is thus legally prepared here.</p>""",
    "25": """<p><strong>wayhî ḇabbōqer wĕhinnēh-hîʾ lēʾāh wayyōʾmer ʾel-lāḇān mah-zōʾt ʿāśîtā llî</strong> — "In the morning — behold, it was Leah!" Jacob's discovery is marked by the same exclamatory <em>hinnēh</em> used at the well-meeting (v2) — but here the surprise is horror, not delight. <em>Lāmmāh rimmîtānî</em> — "why have you deceived me?" — the verb <em>rāmāh</em> (H7411, to throw/betray/deceive) is used here; in 27:35 Jacob is described using <em>mirmāh</em> (deceit, H4820, from the same root) to take Esau's blessing. The verbal link is the narrator's ironic commentary: Jacob, who obtained his father's blessing through deception (<em>mirmāh</em>), is now deceived by the same mechanism (<em>rāmāh</em>).</p>""",
    "26": """<p><strong>lōʾ-yēʿāśeh ḵēn bimmĕqômēnû lātet haṣṣĕʿîrāh lipnê habbĕḵîrāh</strong> — "It is not done this way in our place — to give the younger before the firstborn." Laban's appeal to custom (<em>mišpāṭ</em> implied in <em>yēʿāśeh</em>) as justification turns Jacob's own principle against him: Jacob displaced his older brother; now Laban invokes the elder-before-younger rule to justify the deception. The vocabulary of <em>ṣĕʿîrāh</em> (younger/lesser) and <em>bĕḵîrāh</em> (firstborn/elder) echoes the Esau-Jacob terminology throughout — <em>bĕḵôr</em> (H1060, firstborn) was what Jacob seized from Esau; now Laban uses the <em>bĕḵôr</em> principle to justify depriving Jacob of what he wanted.</p>""",
    "27": """<p><strong>mallēʾ šĕḇuaʿ zōʾt wĕnittĕnāh lĕḵā gam-ʾet-zōʾt</strong> — "Complete this week, and we will give you the other one also." <em>Šāḇûaʿ</em> (H7620, week, period of seven) — the bridal week was the seven-day celebration following a wedding (cf. Judg 14:12 — Samson's seven-day riddle period for the feast). Laban proposes to let Jacob complete the customary bridal week with Leah before receiving Rachel — requiring another seven years of labor in exchange. The double-seven structure (seven years + seven days bridal week + seven more years) saturates the Laban narrative with the "seven" of covenant and completeness, though Laban exploits these patterns for his own gain.</p>""",
    "28": """<p><strong>wayyaʿas yaʿăqōḇ kēn wayyĕmal šĕḇuaʿ zōʾt wayyittēn-lô ʾet-rāḥēl bittô lô lĕʾiššāh</strong> — "Jacob did so; he completed the week with her, and then Laban gave him Rachel his daughter as his wife." The narrative compression — the entire second seven-year period is covered in the first half of v30 — shows that the narrator's interest is in the structural outcome (Jacob's double marriage), not the laboring years. Jacob completes (<em>millēʾ</em> = fulfills, same root as v21's "my days are fulfilled") the bridal week — covenant fidelity even within the exploitative system. His compliance with Laban's terms under duress will generate the covenant grounds for his eventual departure in ch 31.</p>""",
    "29": """<p><strong>wayyittēn lāḇān lĕrāḥēl bittô ʾet-bilhāh šipĕḥātô lāh lĕšipĕḥāh</strong> — "Laban gave his servant Bilhah to Rachel his daughter as her servant." Bilhah's introduction parallels Zilpah's in v24 — both servants are gifts from Laban at the marriage of each daughter. The servant-gift is a dowry custom documented in ANE marriage contracts (the Nuzi tablets contain examples of fathers giving slave-girls to daughters upon marriage, with the stipulation that if the daughter is childless, the slave's children will count as the daughter's). This legal background explains Rachel's surrogate-motherhood proposal in 30:3: she is activating a legally recognized option, not improvising.</p>""",
    "30": """<p><strong>wayyeʾĕhaḇ gam-ʾet-rāḥēl mimmillēʾāh</strong> — "he loved Rachel more than Leah." The comparative construction <em>gam-ʾet-rāḥēl mimmillēʾāh</em> — literally "also Rachel more than Leah" — with <em>min</em> (from/more than) expressing comparison. The double love is stated (Jacob loved both), but the comparative love for Rachel is the narrative tension that drives ch 30. <em>Wayyaʿăḇōḏ ʿimmô ʾôḏ šeḇaʿ-šānîm ʾăḥērôt</em> — "he worked for him another seven years" — the second labor period is dispatched in a single clause. The fourteen-year total is implicit in the structure; Jacob's love is measured in labor.</p>""",
    "31": """<p><strong>wayyarʾ YHWH kî-śĕnûʾāh lēʾāh wayyipteaḥ ʾet-raḥmāh wĕrāḥēl ʿăqārāh</strong> — "When YHWH saw that Leah was hated/unloved, he opened her womb; but Rachel was barren." <em>Śĕnûʾāh</em> (Qal passive participle of <em>śānēʾ</em>, to hate) — the Hebrew term "hated" functions as a comparative idiom in biblical law and narrative: Deut 21:15-17 discusses the rights of the son of the "hated" wife (<em>śĕnûʾāh</em>), meaning the less-favored wife. The "hatred" is comparative, not absolute — Leah is loved less, not despised. <em>Wayyipteaḥ ʾet-raḥmāh</em> — "he opened her womb" — <em>peṯaḥ</em> (to open) applied to <em>reḥem</em> (H7358, womb). Notably, <em>reḥem</em> shares the root with <em>raḥămîm</em> (H7356, compassion, mercy) — God opens the womb in an act of compassionate attention to the unloved woman. YHWH acts where the husband does not love.</p>""",
    "32": """<p><strong>wayyiqrāʾ šĕmô rĕʾûḇen kî ʾāmĕrāh kî-rāʾāh YHWH bĕʿonyî kî ʿattāh yeʾĕhāḇanî ʾîšî</strong> — "She called his name Reuben, for she said, 'YHWH has seen my affliction; surely now my husband will love me.'" The name <em>rĕʾûḇen</em> encodes a wordplay: it sounds like <em>rāʾāh-ben</em> ("see, a son!") and also encodes <em>rāʾāh bĕʿonyî</em> ("YHWH has seen my affliction"). <em>ʿOnî</em> (H6040, affliction, humiliation, misery — from <em>ʿānāh</em>, to be bowed down/afflicted) is the word used for Israel's oppression in Egypt (Exod 3:7, 17: "I have seen the affliction of my people"). Leah's personal affliction anticipates the national affliction of her descendants. The hope "now my husband will love me" (<em>yeʾĕhāḇanî ʾîšî</em>) will be disappointed — the pattern of divine compassion compensating for human lovelessness continues through all four name-sayings in this chapter.</p>""",
    "33": """<p><strong>wayyiqrāʾ šĕmô šimʿôn kî-šāmaʿ YHWH kî-śĕnûʾāh ʾānōḵî wayyittēn-lî gam-ʾet-zeh</strong> — "She named him Simeon, for YHWH has heard that I am unloved, and he gave me this one also." <em>Šimʿôn</em> = "one who hears" — from <em>šāmaʿ</em> (H8085, to hear, to obey). The divine hearing is the covenant mechanism: YHWH hears the cry of the afflicted (Exod 3:7; Ps 22:24; 34:17). Leah's naming of her sons is a running theological commentary: YHWH sees (Reuben), YHWH hears (Simeon), YHWH will join (Levi), I will praise YHWH (Judah). The escalating intimacy of the names — from observed affliction to spontaneous praise — traces Leah's theological journey through the birth of four sons.</p>""",
    "34": """<p><strong>wayyiqrāʾ šĕmô lēwî kî ʾāmĕrāh ʿattāh yillāweh ʾîšî ʾēlay</strong> — "She named him Levi, for she said, 'Now my husband will be joined to me.'" <em>Lēwî</em> from <em>lāwāh</em> (H3867, to join, to accompany, to attach) — the name expresses Leah's hope for conjugal attachment. The Levites' name will carry this meaning forward: in Num 18:2-4, the Levites are "joined" (<em>yillāwû</em>) to Aaron in priestly service — the name of the tribe that becomes the priestly caste encodes the longing of the unbeloved mother to be joined to her husband. The irony deepens: Leah wanted to be joined to Jacob; her descendants will be joined to YHWH in the priesthood.</p>""",
    "35": """<p><strong>wayyiqrāʾ šĕmô yĕhûḏāh kî ʾāmĕrāh happaʿam ʾôḏeh ʾet-YHWH</strong> — "She named him Judah, for she said, 'This time I will praise YHWH.'" <em>Yĕhûḏāh</em> from <em>yādāh</em> (H3034, to throw/praise/give thanks, Hiphil: to praise) — the name means "praise/thanksgiving." In the arc of Leah's four birth-sayings, Judah's naming is the climax: she no longer asks for Jacob's love or God's intervention; she simply praises. The theological movement is from petition (see my affliction) through thanksgiving (God heard) through hope (will be joined) to pure doxology (I will praise). This shift — from petition to praise — is the pattern of the Psalms of lament and the shape of covenant prayer. <em>Waṯṯaʿămōḏ milddet</em> — "and she stopped bearing" — the narrative pause prepares for the crisis of ch 30.</p>"""
  },
  "30": {
    "1": """<p><strong>hāḇāh-lî ḇānîm wĕʾim-ʾayin mētāh ʾānōḵî</strong> — "Give me children, or I will die!" Rachel's outcry frames barrenness as mortal threat. <em>Mētāh ʾānōḵî</em> ("I am dying/I will die") uses the Qal participle — ongoing state of dying rather than a sudden death threat. In the ANE, barrenness was social death: a woman without children had no standing in the household, no security in old age, no memorial after death. Rachel's "I will die" is existential, not merely dramatic. <em>Qānnēʾ</em> — "she was jealous/envied" (Piel of <em>qānāʾ</em>, H7065) — the same verb used for the Philistines' envy of Isaac (26:14) and for God's jealousy (<em>ʾēl qannāʾ</em>, Exod 20:5). The word is strong: active, consuming rivalry.</p>""",
    "2": """<p><strong>hătaḥat ʾĕlōhîm ʾānōḵî ʾăšer mānaʿ mimmēḵ pĕrî-ḇāṭen</strong> — "Am I in the place of God, who has withheld from you the fruit of the womb?" Jacob's rhetorical question is theologically precise: <em>taḥat ʾĕlōhîm</em> (in the place of God) — Jacob cannot grant what God alone controls. <em>Mānaʿ</em> (H4513, to withhold, restrain, deny) — the same verb as in 1 Sam 1:5-6 for Hannah's barrenness (YHWH had closed her womb). <em>Pĕrî-ḇāṭen</em> — "fruit of the womb" — <em>pĕrî</em> (H6529, fruit) applied to the womb uses agricultural language for human fertility (cf. Ps 127:3: "children are a heritage of YHWH, a fruit of the womb his reward"). Jacob's angry response is theologically correct but pastorally tone-deaf — he names the theological truth without the compassion the situation requires.</p>""",
    "3": """<p><strong>wĕtēled ʿal-birkkāy wĕʾibbāneh gam-ʾānōḵî mimmennāh</strong> — "and she will bear on my knees, and I too will be built up through her." The phrase <em>yālaḏ ʿal-birkkāy</em> ("bear on my knees") — a ritual of adoption in the ANE; the one on whose knees the child is placed legally acknowledges the child as their own (cf. 50:23 where Joseph's grandchildren are placed on his knees). Rachel's proposal activates the legal surrogate-mother practice documented in Nuzi tablets. <em>ʾIbbāneh</em> — "I will be built up/have a house" — the Niphal of <em>bānāh</em> (to build), the same root as <em>bēn</em> (son) — a wordplay: "I will be built/have sons" (<em>bānāh</em>/<em>bēn</em>). The social "building" of a household through children is the structural logic of Levirate marriage and surrogate motherhood in the Torah.</p>""",
    "4": """<p><strong>wayyāḇōʾ ʾēleyhā yaʿăqōḇ</strong> — "Jacob slept with her." The narrative compression is characteristic: the event that will generate Dan is stated in five Hebrew words. The narrator records the legal and genealogical outcomes without lingering on the personal dynamics. Bilhah's voicelessness throughout this chapter — she is given, slept with, conceives, bears — contrasts with the vocal theological commentary of Leah and Rachel in naming their children. The matriarchal naming-speeches dominate; the surrogate mothers are recorded by function, not by speech.</p>""",
    "5": """<p><strong>wattar ḇilhāh waṯṯēled lĕyaʿăqōḇ bēn</strong> — "Bilhah conceived and bore Jacob a son." The formulaic birth-record (<em>hārāh... wayyēled</em>) — "conceived and bore" — is the standard genealogical formula of Genesis. Each of the twelve sons follows a variation of this formula, linking the patriarchal family to the creation-genealogy pattern of chs 5 and 10. The use of Jacob's name (<em>lĕyaʿăqōḇ</em>) rather than "her husband" specifies the genealogical fact: the child belongs to Jacob, legally through the surrogate arrangement.</p>""",
    "6": """<p><strong>dānannî ʾĕlōhîm wĕgam šāmaʿ bĕqōlî wayyittēn-lî bēn ʿal-kēn qārĕʾāh šĕmô dān</strong> — "God has vindicated me — he has also heard my voice and given me a son. Therefore she named him Dan." <em>Dānannî</em> — "God has judged/vindicated me" — the Qal perfect of <em>dîn</em> (H1777, to judge, to argue a legal case, to vindicate). Dan's name encodes a legal verdict: God has ruled in Rachel's favor in the rivalry with Leah. The term <em>dîn</em> is used for judicial advocacy throughout the OT (Ps 9:4; 72:4; 82:3). Rachel frames her childlessness as a legal dispute and God's response as judicial vindication. The combination — God judged AND heard — links to the Simeon-naming pattern (YHWH heard Leah's affliction) and shows the two wives appealing to the same divine judicial-compassionate register.</p>""",
    "7": """<p><strong>wattar ʿôḏ waṯṯēled bilhāh šipĕḥat rāḥēl bēn šēnî lĕyaʿăqōḇ</strong> — "Rachel's servant Bilhah conceived again and bore Jacob a second son." The formulaic repetition — "again... bore a second son" — follows the same narrative economy as the Leah-birth sequence. Bilhah's two births are compressed; the theological significance is in Rachel's naming speech in v8, not in the births themselves. The count (<em>šēnî</em>, second) establishes the number of children the surrogate arrangement has produced before Rachel changes strategy.</p>""",
    "8": """<p><strong>naptûlê ʾĕlōhîm niptaltî ʿim-ʾăḥōtî gam-yāḵoltî wayyiqrāʾ šĕmô naptālî</strong> — "With God's wrestlings I have wrestled with my sister, and I have prevailed. So she named him Naphtali." The name <em>naptālî</em> from <em>pātal</em> (H6617, to twist, wrestle, be tortuous) — a rare verb suggesting both physical struggle and moral entanglement. The phrase <em>naptûlê ʾĕlōhîm</em> (wrestlings of God) uses the same root that will appear at Peniel (32:25,28 — though there the verb is <em>ʾāḇaq</em>, to wrestle). The "god-wrestlings" construction uses <em>ʾĕlōhîm</em> as an intensifier (a Hebraism for superlative degree: "tremendous/mighty wrestlings") — the same usage as "mountains of God" (Ps 36:7) for mighty mountains. Rachel's wrestling with her sister through proxy-births anticipates Jacob's wrestling with God — the same family pattern of striving expressed at the personal and cosmic levels.</p>""",
    "9": """<p><strong>waṯṯiqqaḥ ʾet-zilpāh šipĕḥātāh waṯṯittēn ʾōtāh lĕyaʿăqōḇ lĕʾiššāh</strong> — "Leah took her servant Zilpah and gave her to Jacob as a wife." Leah's response to her own cessation of bearing is to mirror Rachel's strategy — giving her servant Zilpah as a surrogate. The symmetry is structural: Rachel → Bilhah → Dan and Naphtali; Leah → Zilpah → Gad and Asher. Four sons are born to the two maidservants, paralleling the four sons already born to Leah directly. The twelve tribes emerge from this pattern of competition, surrogacy, and divine provision — a deeply human process that generates the covenant genealogy.</p>""",
    "10": """<p><strong>waṯṯēled zilpāh šipĕḥat lēʾāh lĕyaʿăqōḇ bēn</strong> — "Leah's servant Zilpah bore Jacob a son." The birth-formula is at its most compressed — no "conceived" (<em>hārāh</em>), just "bore." The formulaic economy accelerates as the birth-sequence multiplies. The twelve-tribe genealogy that will become Israel is generated in a narrative that is both economically told and humanly fraught — the tension between the personal pain of the mothers and the cosmic purpose of the genealogy is held together by the terse narrative style.</p>""",
    "11": """<p><strong>waṯṯōʾmer lēʾāh bāgāḏ wayyiqrāʾ ʾet-šĕmô gāḏ</strong> — "Leah said, 'Good fortune!' and she named him Gad." The exclamation <em>bāgāḏ</em> (or <em>bā gāḏ</em> — "fortune has come") uses <em>gāḏ</em> (H1409, fortune, luck). The Qere/Ketiv textual tradition has two readings: the written text has <em>bāgāḏ</em> (as a single word) while the marginal note reads <em>bā gāḏ</em> (fortune has come). The name Gad is associated with the Canaanite god of fortune in the ancient Near East — though Leah's statement does not invoke the deity but uses the common noun. Isa 65:11 condemns those who "set a table for Gad" — the deity of fortune — suggesting the Canaanite background is present in the name even when not invoked theologically.</p>""",
    "12": """<p><strong>waṯṯēled zilpāh šipĕḥat lēʾāh bēn šēnî lĕyaʿăqōḇ</strong> — "Leah's servant Zilpah bore Jacob a second son." The second birth through Zilpah is noted with the same compressed formula as the first. The narrative's brevity for the surrogate births contrasts with the extended naming speeches for Leah's direct births — the maidservants' children are genealogically registered but narratively backgrounded. The number "second" (<em>šēnî</em>) signals completeness of the Zilpah sequence: two through each maidservant is the pattern.</p>""",
    "13": """<p><strong>waṯṯōʾmer lēʾāh bĕʾošrî kî ʾišĕrûnî ḇānôt wayyiqrāʾ ʾet-šĕmô ʾāšēr</strong> — "Leah said, 'Happy am I! For women will call me happy.' So she named him Asher." <em>ʾĀšēr</em> from <em>ʾeśer</em> (H835, happiness, blessedness, the state of being fortunate) — used in the plural-of-excellence <em>ʾašrê</em> ("Blessed is the one who..."), the beatitude formula of the Psalms (Ps 1:1; 2:12; 32:1-2; etc.). The social dimension — "women will call me happy" (<em>ʾišĕrûnî ḇānôt</em>) — shows that Leah's sense of blessedness is validated by female community recognition; her social standing is being restored through sons. The Asher tribe will receive Moses's blessing: "Let Asher be blessed more than other sons... dip his foot in oil" (Deut 33:24).</p>""",
    "14": """<p><strong>wayyēlek rĕʾûḇēn bîmê qĕṣîr-ḥiṭṭîm wayyimṣāʾ dûḏāʾîm baśśāḏeh</strong> — "During the wheat harvest Reuben went and found mandrakes in the field." <em>Dûḏāʾîm</em> (H1736, mandrakes — Mandragora officinarum) — a plant with a forked root that resembles a human figure; the name may derive from <em>dôḏ</em> (H1730, beloved, uncle, love-token), connecting mandrakes to love and sexuality. Mandrakes were widely believed in the ANE and Mediterranean world to be aphrodisiacs and fertility stimulants — the Mishnah and Pliny both reference their use. The timing — wheat harvest — dates this to May/June. Reuben's discovery by his firstborn son is significant: the elder (who will lose his birthright) brings the fertility plant that will ironically not help Rachel (her children come from God, not mandrakes) but will help Leah conceive again.</p>""",
    "15": """<p><strong>halĕʾāṭ qāḥalt ʾet-ʾîšî wĕlāqaḥat gam ʾet-dûḏāʾê bĕnî</strong> — "Was it not enough that you took my husband? Will you also take my son's mandrakes?" Leah's accusation — "you took my husband" (<em>qāḥalt ʾet-ʾîšî</em>) — is the bitterest statement of the Rachel-Leah rivalry: Jacob's love for Rachel constitutes a form of husband-taking from Leah's perspective. The subsequent arrangement (Rachel trades Jacob's conjugal time for mandrakes) is darkly ironic: Rachel gets the reputed fertility plant but will only conceive through divine action (v22); Leah, who gives up the mandrakes, conceives immediately from the traded conjugal night (v17). The mandrakes are shown to be irrelevant — it is God who opens and closes wombs.</p>""",
    "16": """<p><strong>śāḵōr śĕḵartîḵā bĕdûḏāʾê bĕnî</strong> — "I have hired you with my son's mandrakes." The emphatic infinitive absolute <em>śāḵōr śĕḵartîḵā</em> (hiring I have hired you) — Leah addresses Jacob with the same assertiveness Rachel showed in v1 ("give me children"). The word <em>śāḵōr</em>/<em>śāḵar</em> (H7936/H7939, to hire, wages) is the commercial-contract term that dominates the Jacob-Laban narrative (29:15; 30:28,32-33; 31:7,41). Leah now applies it to her own marriage: she has "hired" her husband's conjugal attention with mandrakes. The irony of the commercial language applied to marriage is the narrator's sharp commentary on the state of the household.</p>""",
    "17": """<p><strong>wayyišmaʿ ʾĕlōhîm ʾel-lēʾāh waṯṯahar waṯṯēled lĕyaʿăqōḇ bēn ḥămîšî</strong> — "God heard Leah, and she conceived and bore Jacob a fifth son." The divine hearing (<em>šāmaʿ ʾĕlōhîm</em>) directly following the mandrake-for-conjugal-night exchange makes the theological point: God's hearing is what produces the conception, not the mandrakes Rachel has just obtained. The fifth son is the fifth direct birth Leah produces — she has now borne more children than any other woman in Jacob's household. God's consistent attention to the unloved wife is one of Genesis's sustained theological statements about divine preferential care for the vulnerable.</p>""",
    "18": """<p><strong>nātan ʾĕlōhîm śĕḵārî ʾăšer nātattî šipĕḥātî lĕʾîšî wayyiqrāʾ šĕmô yiśśāḵār</strong> — "God has given me my wages because I gave my servant to my husband. So she named him Issachar." <em>Yiśśāḵār</em> — the etymology here is folk: "there is reward/wages" (<em>yēš śāḵār</em>) or "man of wages" (<em>ʾîš śāḵār</em>). Leah interprets the birth as divine payment (<em>śāḵar</em>, H7939) for giving Zilpah as surrogate. The commercial vocabulary returns: the birth is <em>śāḵār</em> (wages), as if God has settled the labor account. The Issachar tribe receives a distinctive blessing in Gen 49:14-15 — a strong donkey crouching between two burdens, accepting conscript labor — which may echo the labor/wages etymology of the name.</p>""",
    "19": """<p><strong>waṯṯahar ʿôḏ lēʾāh waṯṯēled bēn-šiššî lĕyaʿăqōḇ</strong> — "Leah conceived again and bore Jacob a sixth son." The sixth son of Leah (including two through Zilpah) — the number "six" (<em>šiššî</em>) becomes part of Leah's naming speech in v20: "because I bore him six sons." The count matters: at six sons, Leah has generated more than half the tribal fathers of Israel through her own household (direct + surrogate). The sixth birth marks the completion of Leah's bearing sequence before the birth of Dinah (v21).</p>""",
    "20": """<p><strong>zĕḇālanî ʾĕlōhîm ʾōtî zeḇed ṭôḇ happaʿam yizĕḇĕlēnî ʾîšî kî-yālaḏtî lô šiššāh ḇānîm wayyiqrāʾ ʾet-šĕmô zĕḇûlûn</strong> — "God has endowed me with a precious endowment. This time my husband will honor/dwell with me." <em>Zĕḇûlûn</em> — from <em>zāḇal</em> (H2082, to dwell, to honor/exalt); the name plays on <em>zeḇed</em> (H2065, a gift/endowment) and <em>zāḇal</em>. Two meanings operate: (1) God has gifted me (<em>zeḇed ṭôḇ</em>, a good gift); (2) my husband will now honor/dwell with me (<em>yizĕḇĕlēnî</em>). Leah's hope for Jacob's honor/habitation — articulated at son #1 (Reuben: "now my husband will love me") and again at son #6 — shows that the desire for covenantal conjugal presence remains unfulfilled. The six sons have not secured what Leah ultimately wants.</p>""",
    "21": """<p><strong>wĕʾaḥar yālaḏāh bat waṯṯiqrāʾ ʾet-šĕmāh dînāh</strong> — "Afterwards she bore a daughter and named her Dinah." The one daughter named in the Jacob narrative — <em>Dînāh</em>, from <em>dîn</em> (to judge) — is introduced without birth-speech or etymology, in contrast to every son. The brevity of her introduction contrasts with the extended narrative she will receive in ch 34 (Dinah and Shechem). Her name's root (<em>dîn</em>, judgment) anticipates the violent "judgment" her brothers will enact on Shechem. The fact that she is named at all, while other daughters are not mentioned (31:41 says Jacob had daughters), marks her as significant for the subsequent narrative.</p>""",
    "22": """<p><strong>wayyizkor ʾĕlōhîm ʾet-rāḥēl wayyišmaʿ ʾēleyhā ʾĕlōhîm wayyipteaḥ ʾet-raḥmāh</strong> — "God remembered Rachel; God heard her and opened her womb." The formula <em>wayyizkor ʾĕlōhîm</em> (God remembered) — the <em>zāḵar</em> (H2142) covenant-memory verb — is used for God's response to covenant distress: 8:1 (God remembered Noah), 19:29 (God remembered Abraham for Lot), Exod 2:24 (God remembered the covenant with Abraham/Isaac/Jacob for enslaved Israel). Rachel's remembrance follows the same covenantal pattern: the memory is not mere recollection but active intervention. The triad — remembered / heard / opened — compresses three divine actions into one verse. The "opening" of the womb (<em>peṯaḥ raḥmāh</em>) uses the same verb as in 29:31 for Leah.</p>""",
    "23": """<p><strong>wathar waṯṯēled bēn waṯṯōʾmer ʾāsap ʾĕlōhîm ʾet-ḥerpātî</strong> — "She conceived and bore a son and said, 'God has taken away my reproach.'" <em>ʾĀsap ʾĕlōhîm ʾet-ḥerpātî</em> — "God has gathered/removed my reproach." <em>ʾĀsap</em> (H622, to gather, remove, take away) — one of the Joseph etymologies; the other is in v24 (<em>yāsap</em> = may he add). <em>Ḥerpāh</em> (H2781, reproach, disgrace) — in the ANE and OT, barrenness was experienced as social shame/reproach: the barren woman had failed her primary social duty. Hannah uses the same word (1 Sam 1:6-11); Elizabeth in Luke 1:25 ("he has taken away my reproach among men") uses the same theological language. The removal of reproach is divine vindication of the woman the social order had judged as deficient.</p>""",
    "24": """<p><strong>waṯṯiqrāʾ ʾet-šĕmô yôsēp lēʾmōr yōsēp YHWH lî bēn ʾaḥēr</strong> — "She named him Joseph, saying, 'May YHWH add to me another son.'" The name <em>yôsēp</em> encodes two etymologies simultaneously: (1) from <em>ʾāsap</em> (v23, "God has removed my reproach") — the <em>ʾāsap</em> root; (2) from <em>yāsap</em> (H3254, to add, to continue) — the prayer for a second son. The name is a bilingual pun: it looks backward (reproach removed) and forward (may God add more). The two-directional naming formula is unique in the Genesis birth-speeches. Joseph's name thus carries both gratitude and hope — which characterizes his entire narrative: what is lost is restored and multiplied. YHWH's name is invoked — the covenant name — marking the prayer as more than a fertility wish.</p>""",
    "25": """<p><strong>wayhî kaʾăšer yālaḏāh rāḥēl ʾet-yôsēp wayyōʾmer yaʿăqōḇ ʾel-lāḇān šallĕḥēnî wĕʾēlĕḵāh ʾel-mĕqômî ûlĕʾarṣî</strong> — "When Rachel had borne Joseph, Jacob said to Laban, 'Send me away that I may go to my place and to my land.'" The birth of Joseph is the trigger for Jacob's departure request — suggesting that in Jacob's mind, Joseph's birth completed a cycle. The phrase <em>mĕqômî ûlĕʾarṣî</em> (my place and my land) uses <em>māqôm</em> (H4725, place) — a term that acquired sacred resonance in Jacob's journey: the "place" where he slept at Bethel (28:11,16-17) and the "place" of Peniel (32:31). Jacob's homeland is both geographical and covenantally charged.</p>""",
    "26": """<p><strong>tĕnāh ʾet-nāšay wĕʾet-yĕlāḏay ʾăšer ʿāḇaḏtî ʾōtĕḵā bāhen wĕʾēlēḵāh</strong> — "Give me my wives and my children for whom I have served you, and I will go." The legal claim is precise: Jacob's wives and children are the result of his labor-contract (<em>ʿāḇaḏtî ʾōtĕḵā bāhen</em>, "I served you for them"). In the ANE labor-contract framework, a laborer who worked for a bride-price had rights to the bride and her children — they were legally his even if born in the employer's household. Jacob's claim is legally grounded: the fourteen years of labor have purchased his household, and he is entitled to take them.</p>""",
    "27": """<p><strong>niḥaštî wayyĕḇāreḵēnî YHWH biglālĕḵā</strong> — "I have divined that YHWH has blessed me because of you." Laban uses the verb <em>nāḥaš</em> (H5172, to practice divination, to observe signs, to divine) — a term for omen-reading and divination practices common in the ANE (Num 23:23; Deut 18:10 prohibit it for Israel). Laban is a diviner who has discerned through his oracular practices that Jacob's presence is the source of YHWH's blessing on his household. The irony: a Aramean diviner attributes his prosperity to the God of Abraham, Isaac, and Jacob. The theological truth he names correctly (<em>YHWH has blessed me because of you</em>) is the same truth Joseph's Egyptian masters will discern (39:3, 5).</p>""",
    "28": """<p><strong>nāqĕḇāh śĕḵārĕḵā ʿālay wĕʾettēnāh</strong> — "Name your wages and I will give it." Laban's invitation to Jacob to set his own wages is the same opening gambit as 29:15 — Laban invites Jacob to name terms in a negotiation Laban intends to control. The verb <em>nāqaḇ</em> (H5344, to pierce, to designate/specify) — "designate/specify your wages" — is a technical term for naming a price or figure explicitly. Laban will subsequently manipulate the terms (31:7: he changed Jacob's wages ten times), so the invitation to "name your wages" is less generous than it sounds.</p>""",
    "29": """<p><strong>ʾattāh yāḏaʿtā ʾēt ʾăšer ʿăḇaḏtîḵā wĕʾēt ʾăšer-hāyāh miqnĕḵā ʾittî</strong> — "You know how I have served you and how your livestock has fared with me." Jacob's appeal to Laban's own knowledge (<em>ʾattāh yāḏaʿtā</em>) is a rhetorical strategy — making Laban the acknowledging witness to Jacob's faithful labor. The verb <em>yāḏaʿ</em> (to know) here functions as evidence-appeal: you have seen, you know, the facts are as I state them. Jacob does not merely assert his good service; he calls Laban as his own witness. The livestock's prosperity "with me" (<em>ʾittî</em>) echoes the covenant formula "YHWH was with Jacob" — the implication is that YHWH's presence with Jacob produced the flourishing.</p>""",
    "30": """<p><strong>kî mĕʿaṭ ʾăšer-hāyāh lĕḵā lĕpānay wayyiprōṣ lārōḇ wayyĕḇāreḵ YHWH ʾōtĕḵā lĕraglî</strong> — "For the little you had before I came has grown greatly, and YHWH has blessed you wherever I walked." The phrase <em>lĕraglî</em> (literally "at my feet," meaning wherever I went/because of me) echoes the language of the covenant blessing through Abraham (12:3: "through you all nations will be blessed"). Jacob is the carrier of the Abrahamic blessing, and Laban has been the incidental beneficiary. <em>Wayyiprōṣ lārōḇ</em> — "he has burst forth greatly" — the verb <em>pāraṣ</em> (H6555, to break through, burst forth) used here will be applied to Jacob himself in 28:14 (your offspring will "burst forth" in all directions) and to Joseph's increase in Egypt.</p>""",
    "31": """<p><strong>lōʾ-tittēn-lî mĕʾûmāh ʾim-taʿăśeh-llî haddāḇār hazzeh</strong> — "You shall not give me anything; if you will do this one thing for me." Jacob's counter-proposal reverses Laban's offer: instead of a wage paid in existing livestock, Jacob will take only the future offspring of a specific category. The apparent generosity ("give me nothing") is the opening of a strategic arrangement. <em>Mĕʾûmāh</em> (H3972, anything, something) — the strongest negative: "not a single thing." Jacob's refusal of existing payment while claiming future increase reflects his confidence in divine provision (which will be confirmed in 31:10-13).</p>""",
    "32": """<p><strong>kol-śeh nāqōḏ wĕṭālûʾ wĕḵol-śeh-ḥûm baḵḵĕśāḇîm</strong> — "every speckled and spotted sheep and every dark lamb." The animal-classification system — speckled (<em>nāqōḏ</em>, H5348), spotted (<em>ṭālûʾ</em>, H2921), dark/black (<em>ḥûm</em>, H2345) — establishes the wage-category. The rarer colors (in a flock where solid-colored animals predominate) are Jacob's wages. Laban will remove all existing striped/spotted animals to his sons' care (v35), so Jacob begins with zero of the designated animals. His future increase will be entirely from the solid-colored breeding stock — which makes the subsequent proliferation of striped/spotted offspring miraculous.</p>""",
    "33": """<p><strong>wĕʿānĕtāh bî ṣiḏqātî bĕyôm māḥār</strong> — "and my honesty will answer for me in the future." <em>Ṣiḏqāh</em> (H6666, righteousness, justice, what is right) — Jacob appeals to his integrity (<em>ṣĕḏāqāh</em>) as the guarantor of the agreement. The phrase <em>ʿānāh bî</em> (answer for/testify against me) positions righteousness as a witness that will speak on Jacob's behalf — the same personification of righteousness as a covenant witness that appears in the Psalms and prophets (Ps 85:10-11: "righteousness and peace have kissed"). Jacob's appeal to his own righteousness before God is bold — it will be tested by the subsequent narrative.</p>""",
    "34": """<p><strong>hēn lû yĕhî kiḏĕḇāreḵā</strong> — "Good, let it be as you say." Laban's quick agreement — no negotiation, no counter-offer — reveals his confidence that the arrangement favors him. He has removed all existing striped animals to a three-day journey's distance (v35), ensuring Jacob starts with nothing. From Laban's perspective, the odds of sufficient striped offspring emerging from a solid-colored flock to constitute meaningful wages are low. Laban's confidence is entirely rational by ordinary agronomy; what he does not factor is divine intervention.</p>""",
    "35": """<p><strong>wayyāsar bayyôm hahûʾ ʾet-hattĕyāšîm hāʿăquddîm wĕhaṭṭĕlūʾîm</strong> — "That same day he removed all the male goats that were streaked or spotted." Laban's immediate action — removing all existing striped/spotted animals on the same day — closes every natural pathway to Jacob's wages. <em>Hāʿăquddîm</em> (striped/banded, H6124) and <em>haṭṭĕlūʾîm</em> (spotted, H2921) — the same categories Jacob proposed. <em>Wayyittēn bĕyad-bānāyw</em> — "he gave them into the hand of his sons" — Laban puts his own sons in charge of the separated flock, ensuring Jacob has no access. The three-day journey's distance (v36) creates a geographic buffer. Laban's manipulation is thorough; God's provision will be thorougher.</p>""",
    "36": """<p><strong>wayyāśem derek šĕlōšet yāmîm bênô ûḇên yaʿăqōḇ</strong> — "He put a three-day journey between himself and Jacob." <em>Derek šĕlōšet yāmîm</em> (three days' journey distance) is the maximum practical separation in pastoral travel — far enough that the flocks cannot intermingle or be secretly transferred. The same "three days' journey" will appear in the Exodus narrative (3:18; 5:3) for the distance into the wilderness Israel requests for worship — another connection between the Jacob-Laban narrative and the Exodus typology.</p>""",
    "37": """<p><strong>wayyiqqaḥ-lô yaʿăqōḇ maqqal liḇneh laḥ wĕlûz weʿarĕmôn wayyĕpaṣṣēl bāhen paṣṣĕlôt lĕḇānôt</strong> — "Jacob took fresh branches of poplar, almond, and plane trees and peeled white streaks on them." Jacob's branch-peeling technique — creating striped branches in the watering troughs — is folk-genetic practice based on the ancient belief that what a pregnant animal sees during conception affects the offspring's appearance. The three tree species (<em>liḇneh</em> = poplar/white wood; <em>lûz</em> = almond; <em>ʿarĕmôn</em> = plane/chestnut) produce white inner wood when stripped. Whether this technique could actually affect animal coloration is biologically questioned; the narrative's own answer comes in 31:10-12 where God reveals to Jacob in a dream that he (God) has been causing the striped offspring — the branches are not the mechanism.</p>""",
    "38": """<p><strong>wayyaṣṣēg ʾet-hammaqqĕlôt ʾăšer piṣṣēl bārehaṭîm bĕšiqĕtôt hammayim</strong> — "He placed the peeled branches in the troughs, in the watering channels, in front of the flocks." The watering troughs (<em>rahaṭîm</em>, H7298) are the site of Jacob's intervention. The connection to the well-meeting of ch 29 is deliberate: the same wells/troughs where Jacob met Rachel and rolled the stone are now the site of Jacob's prosperity scheme. The narrative geography is coherent. The timing — placing branches "when the flocks came to drink, since they mated when they came to drink" (<em>baʿălōt haṣṣōʾn liḇôʾ lišĕtôt</em>) — shows Jacob's understanding of pastoral seasonality.</p>""",
    "39": """<p><strong>wayyeḥĕmû haṣṣōʾn ʾel-hammaqqĕlôt wayyēlĕḏû haṣṣōʾn ʿăquddîm nĕquddîm ûṭĕluʾîm</strong> — "The flocks bred in front of the branches and bore streaked, speckled, and spotted young." The three result-categories match the three wage-categories Jacob proposed (v32): streaked (<em>ʿăquddîm</em>), speckled (<em>nĕquddîm</em>), spotted (<em>ṭĕluʾîm</em>). The supernatural proliferation of the minority-colored offspring defies ordinary agronomy — this is the point the narrative is building toward. Jacob's scheme (branches) appears to be the cause; God's dream-revelation (31:10-12) will clarify that the breeding was divinely orchestrated through Jacob's selective pairing, not through the branches' magical influence on conception.</p>""",
    "40": """<p><strong>wayyapred yaʿăqōḇ ʾet-haḵĕśāḇîm wayyittēn pĕnê haṣṣōʾn ʾel-ʿāqōḏ wĕḵol-ḥûm bĕṣōʾn lāḇān</strong> — "Jacob set apart the lambs and had the flocks face toward the streaked and dark animals of Laban." The selective pairing strategy — having the solid-colored females face striped/dark animals during mating — reflects Jacob's understanding of selective breeding, whatever folk-genetic theory underlies it. <em>Wayĕhî-lô ʿăḏārîm lĕḇaddô</em> — "he made separate flocks for himself and did not put them with Laban's" — Jacob maintains strict separation of his emerging flock from Laban's, preventing intermingling that would muddy the ownership claim.</p>""",
    "41": """<p><strong>wĕhāyāh bĕkol-yaḥēm haṣṣōʾn hamĕquššārôt wĕśām yaʿăqōḇ ʾet-hammaqqĕlôt lĕʿênê haṣṣōʾn bārehaṭîm lĕyaḥamnāh bammaqqĕlôt</strong> — "Whenever the stronger females were in heat, Jacob placed the branches in the troughs in front of the animals." The selective application — branches only for the "strong/vigorous" (<em>meqûššārôt</em>, H6989, knotted/vigorous) females — is Jacob's key economic insight: he reserves his breeding intervention for the productive stock. The Hebrew <em>meqûššārôt</em> is a hapax legomenon (appears only here) — possibly related to <em>qāšar</em> (to bind/be strong).</p>""",
    "42": """<p><strong>ûbĕhaʿăṭip haṣṣōʾn lōʾ yāśîm</strong> — "but for the weak animals he would not place them." The weak animals (<em>haʿăṭupîm</em>, H5848, the faint/feeble ones) produce Laban's share; the strong ones (<em>hameqūšārôt</em>) produce Jacob's. The result is that Jacob's flock is selectively composed of robust stock while Laban's declines in quality — an outcome that 31:9 attributes directly to God's action: "God has taken away your father's livestock and given them to me." The breeding scheme is presented as Jacob's stratagem, but the theological framing makes God the agent.</p>""",
    "43": """<p><strong>wayyiprōṣ hāʾîš mĕʾōḏ mĕʾōḏ wayhî-lô ṣōʾn rabbôt ûšĕpāḥôt waʿăḇāḏîm ûgĕmallîm waʿăḇāḏîm wăḥămōrîm</strong> — "So the man grew exceedingly great and came to have large flocks, and female and male servants, and camels and donkeys." The accumulation formula <em>mĕʾōḏ mĕʾōḏ</em> (very very much) — the same double superlative used for Abraham's covenant wealth (17:2) and Isaac's Philistine-envied prosperity (26:13-14). Jacob's prosperity follows the same covenant-blessing pattern. The four-category inventory (flocks, female servants, male servants, camels and donkeys) mirrors the wealth formulas used for Abraham (12:16; 24:35) — Jacob is being established as a third-generation carrier of the Abrahamic covenant prosperity. The chapter ends where it began, with the matriarchal rivalry — but now Jacob's prosperity is the narrative frame enclosing both the domestic strife and the divine provision.</p>"""
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_ORIGINAL)
    save_comm('mkt-original', 'genesis', existing)

    result = load_comm('mkt-original', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [29, 30]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis total: {total_chs} chapters, {total_vv} verses with original data')
    print('Genesis 29-30 mkt-original written.')

if __name__ == '__main__':
    main()
